css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
   width: 70px;
   height: 40px;
   outline: 2px solid currentColor;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) 0 0/8px 8px no-repeat, linear-gradient(currentColor 0 0) 50%/10px 100% no-repeat, conic-gradient(from 90deg at 10px 10px,#0000 90deg,currentColor 0), conic-gradient(from -90deg at 60px 30px,#0000 90deg,currentColor 0);
   animation: l4 2s infinite;
}
@keyframes l4  {
  0% {background-position:0 0 ,50%;
  clip-path:circle(15px at left 4px top 4px)}
12.5% {background-position:50% 0 ,50%;
  clip-path:circle(15px at left 50% top 4px)}
25% {background-position:50% 100%,50%;
  clip-path:circle(15px at left 50% bottom 4px)}
37.5% {background-position:100% 100%,50%;
  clip-path:circle(15px at right 4px bottom 4px)}
50% {background-position:100% 0 ,50%;
  clip-path:circle(15px at right 4px top 4px)}
62.5% {background-position:50% 0 ,50%;
  clip-path:circle(15px at right 50% top 4px)}
75% {background-position:50% 100%,50%;
  clip-path:circle(15px at right 50% bottom 4px)}
82.5% {background-position:0 100%,50%;
  clip-path:circle(15px at left 4px bottom 4px)}
100% {background-position:0 0 ,50%;
  clip-path:circle(15px at left 4px top 4px)}
}
